[Collection("Integration")]
public class UsersApiTests : IClassFixture<TestAppFactory>
{
    private readonly HttpClient _client;

    public UsersApiTests(TestAppFactory factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task CreateUser_WithValidData_ReturnsCreatedWithId()
    {
        // Arrange
        var request = new CreateUserRequest(
            "John Doe",
            "john@example.com",
            "password123"
        );

        // Act
        var response = await _client.PostAsJsonAsync("/api/v1/users", request);

        // Assert
        response.StatusCode.Should().Be(System.Net.HttpStatusCode.Created);
        var user = await response.Content.ReadFromJsonAsync<UserResponse>();
        user.Should().NotBeNull();
        user.Name.Should().Be("John Doe");
        user.Email.Should().Be("john@example.com");
    }

    [Fact]
    public async Task GetUser_WhenNotFound_Returns404()
    {
        // Act
        var response = await _client.GetAsync("/api/v1/users/999");

        // Assert
        response.StatusCode.Should().Be(System.Net.HttpStatusCode.NotFound);
    }
}

