public class UserServiceTests
{
    private readonly Mock<IUserRepository> _mockRepo;
    private readonly UserService _service;

    public UserServiceTests()
    {
        _mockRepo = new Mock<IUserRepository>();
        _service = new UserService(_mockRepo.Object);
    }

    [Fact]
    public async Task Create_WithValidData_ReturnsUser()
    {
        // Arrange
        var request = new CreateUserRequest("John", "john@example.com", "password");
        var savedUser = new User { Id = 1, Name = "John", Email = "john@example.com" };
        _mockRepo.Setup(r => r.SaveAsync(It.Is<User>(u => u.Email == "john@example.com")))
            .ReturnsAsync(savedUser);

        // Act
        var result = await _service.Create(request);

        // Assert
        result.Should().NotBeNull();
        result.Id.Should().Be(1);
        _mockRepo.Verify(r => r.SaveAsync(It.IsAny<User>()), Times.Once);
    }

    [Theory]
    [InlineData("", false)]
    [InlineData("valid@example.com", true)]
    public async Task Create_EmailValidation(string email, bool shouldSucceed)
    {
        // Arrange
        var request = new CreateUserRequest("John", email, "password");

        // Act & Assert
        if (shouldSucceed)
        {
            var result = await _service.Create(request);
            result.Should().NotBeNull();
        }
        else
        {
            await FluentActions.Invoking(() => _service.Create(request))
                .Should().ThrowAsync<ValidationException>();
        }
    }
}

