public class UserBuilder
{
    private long _id = 1;
    private string _name = "John Doe";
    private string _email = "john@example.com";
    private string _password = "password123";

    public UserBuilder WithId(long id)
    {
        _id = id;
        return this;
    }

    public UserBuilder WithEmail(string email)
    {
        _email = email;
        return this;
    }

    public User Build()
    {
        return new User { Id = _id, Name = _name, Email = _email, Password = _password };
    }
}

// Usage
[Fact]
public async Task FindUser_ReturnsUser()
{
    var user = new UserBuilder().WithEmail("special@example.com").Build();
    _mockRepo.Setup(r => r.FindByEmailAsync(user.Email)).ReturnsAsync(user);

    var result = await _service.FindByEmail(user.Email);
    result.Email.Should().Be("special@example.com");
}

[Fact]
public void User_Comparison()
{
    var expected = new UserResponse { Id = 1, Name = "John", Email = "john@example.com" };
    var actual = new UserResponse { Id = 1, Name = "John", Email = "jane@example.com" };

    actual.Should().BeEquivalentTo(expected);
    // Failure output:
    // Expected user.Email to be "john@example.com", but found "jane@example.com".
}

[Fact]
public void User_Comparison()
{
    var expected = new UserResponse { Id = 1, Name = "John", Email = "john@example.com" };
    var actual = new UserResponse { Id = 1, Name = "John", Email = "jane@example.com" };

    Assert.Equal(expected, actual);
    // Failure output: Expected UserResponse { Id = 1, Name = John, Email = john@example.com } but got UserResponse { Id = 1, Name = John, Email = jane@example.com }
    // Hard to spot the difference at a glance.
}
